function solve(s) {
    const n = s.length;
    // We are looking for the *smallest* index i such that s[i] == s[n - i - 1].
    // We should iterate i starting from 0 up to the midpoint (floor((n-1)/2)).
    // However, the problem statement implies checking all possible 'i' up to a point 
    // where the two indices might be considered.

    // Let's re-examine the examples and the definition of i.
    // The indices are 0, 1, ..., n-1.
    // We check i and its symmetric counterpart n-1-i.

    // The constraints on i are usually 0 <= i < n.
    // If we iterate i from 0 up to n-1, we check every position.

    // Example 1: s = "abcacbd", n=7
    // i=0: s[0]='a', s[6]='d'. 'a' != 'd'.
    // i=1: s[1]='b', s[5]='b'. 'b' == 'b'. Return 1. (Matches example)

    // Example 2: s = "abc", n=3
    // i=0: s[0]='a', s[2]='c'. 'a' != 'c'.
    // i=1: s[1]='b', s[1]='b'. 'b' == 'b'. Return 1. (Matches example)

    // Example 3: s = "abcdab", n=6
    // i=0: s[0]='a', s[5]='b'. 'a' != 'b'.
    // i=1: s[1]='b', s[4]='a'. 'b' != 'a'.
    // i=2: s[2]='c', s[3]='d'. 'c' != 'd'.
    // i=3: s[3]='d', s[2]='c'. (If we continue past the midpoint, we find duplicates, but we need the *smallest* i).
    // The iteration should stop when i > n - 1 - i, i.e., 2i > n - 1, or i > (n-1)/2.

    // Since we need the *smallest* i, iterating from i = 0 upwards is correct.
    // The maximum i we need to check is when i is the last index before it repeats the pair (or is the center).
    // We only need to check up to i <= n - 1 - i, which means 2*i <= n - 1, or i <= (n-1)/2.

    const limit = Math.floor((n - 1) / 2);

    for (let i = 0; i <= limit; i++) {
        const j = n - 1 - i;
        if (s[i] === s[j]) {
            return i;
        }
    }

    // If the loop finishes, no such index was found in the necessary range.
    // We must consider if the problem implies we must check *all* i from 0 to n-1.
    // Let's re-read the example 1 explanation: "In index i=1, s[1] and s[5] are both 'b'."
    // For i=1, j=5. 1 < 5. This is covered by i <= limit.

    // If s="abc", n=3. limit = floor(2/2) = 1.
    // i=0: j=2. s[0]!=s[2].
    // i=1: j=1. s[1]==s[1]. Return 1. (Matches example 2)

    // If s="abcdab", n=6. limit = floor(5/2) = 2.
    // i=0: j=5. s[0]!=s[5].
    // i=1: j=4. s[1]!=s[4].
    // i=2: j=3. s[2]!=s[3].
    // Loop ends. Return -1. (Matches example 3)

    // The iteration up to floor((n-1)/2) covers all unique pairs (i, n-1-i) including the center element when n is odd.

    return -1;
}

