func solve(s string) int64 {
	n := len(s)
	// We are looking for the smallest index i such that s[i] == s[n - i - 1].
	// We iterate i starting from 0. We only need to check up to the midpoint,
	// as checking beyond that just re-checks pairs we already checked (e.g., if we check i=5 for n=7, we check (5, 1), which is the same pair as i=1).
	// The loop limit should be such that i <= n - 1 - i, which means 2*i <= n - 1, or i <= (n - 1) / 2.
	// Since we are using integer division, i <= (n-1)/2 is equivalent to i <= floor((n-1)/2).

	for i := 0; i*2 <= n-1; i++ {
		j := n - 1 - i
		if s[i] == s[j] {
			return int64(i)
		}
	}

	// If no such index is found.
	return -1
}
```

