func solve(s string) int64 {
	n := len(s)

	// We are looking for the smallest index i such that s[i] == s[n - i - 1].
	// Since we want the *smallest* i, we iterate i starting from 0 upwards.
	// We only need to iterate up to the point where i is less than or equal to its symmetric index n - i - 1.
