    // i=0: j=5. s[0]!=s[5].
    // i=1: j=4. s[1]!=s[4].
    // i=2: j=3. s[2]!=s[3].
    // Loop ends. Return -1. (Matches example 3)

    // The iteration up to floor((n-1)/2) covers all unique pairs (i, n-1-i) including the center element when n is odd.

    return -1;
}
